arguments.command:
cat .ddx/beads.jsonl | python3 -c "
import sys, json
beads = []
for line in sys.stdin:
    line = line.strip()
    if line:
        beads.append(json.loads(line))

# Get latest state per bead id
latest = {}
for b in beads:
    bid = b.get('id')
    if bid:
        latest[bid] = b

# Filter open (not closed/done/wontfix)
closed = {'closed', 'done', 'wontfix', 'cancelled', 'canceled', 'complete', 'completed'}
open_beads = [b for b in latest.values() if b.get('status','').lower() not in closed]

# Sort by priority then id
def prio_key(b):
    p = b.get('priority', 'medium')
    order = {'critical': 0, 'high': 1, 'medium': 2, 'low': 3}
    return (order.get(p.lower(), 99), b.get('id',''))

open_beads.sort(key=prio_key)

for b in open_beads:
    print(f\"ID: {b.get('id','?')} | Priority: {b.get('priority','?')} | Status: {b.get('status','?')} | Title: {b.get('title','?')}\")
" 2>&1 | head -100

